# inventory/overlap_detector.py
from collections import defaultdict

def detect_overlaps(tools: list[GenAIToolRecord]) -> dict[str, list[str]]:
    """
    Returns a dict mapping capability → list of tool_ids that provide it.
    Only includes capabilities with 2+ tools (actual overlaps).
    Ignores tools that are free-tier or not in production.
    """
    cap_to_tools = defaultdict(list)
    for tool in tools:
        if not tool.in_production or tool.contract_type == "free_tier":
            continue
        for cap in tool.capabilities:
            cap_to_tools[cap].append(tool.tool_id)

    return {
        cap: tool_ids
        for cap, tool_ids in cap_to_tools.items()
        if len(tool_ids) >= 2
    }

def score_overlap(capability: str, tools_in_overlap: list[GenAIToolRecord]) -> dict:
    """Score an overlap to prioritise the rationalization effort."""
    total_spend = sum(t.monthly_spend or 0 for t in tools_in_overlap)
    team_count  = len({team for t in tools_in_overlap for team in t.using_teams})
    compliance_gaps = sum(
        1 for t in tools_in_overlap
        if not t.due_diligence_done or not t.dpa_signed
    )

    return {
        "capability":        capability,
        "tool_count":        len(tools_in_overlap),
        "monthly_spend":     total_spend,
        "affected_teams":    team_count,
        "compliance_gaps":   compliance_gaps,
        "priority_score":    total_spend / 100 + team_count * 5 + compliance_gaps * 20,
        # Higher score = higher priority to rationalize
    }
